// ============================================================
// STATE
// ============================================================
const state = {
  currentSection: 'dashboard',
  darkMode: false,
  completedTopics: new Set(),
  masteredCards: new Set(),
  flashcardIndex: 0,
  flashcardFlipped: false,
  flashcardDeck: [],
  notes: [],
  sessions: [],
  timerSeconds: 0,
  timerRunning: false,
  timerInterval: null,
};

function loadState() {
  try {
    const s = JSON.parse(localStorage.getItem('ibdp-bm-v2') || '{}');
    state.completedTopics = new Set(s.completedTopics || []);
    state.masteredCards = new Set(s.masteredCards || []);
    state.darkMode = s.darkMode || false;
    state.notes = s.notes || [];
    state.sessions = s.sessions || [];
  } catch(e) {}
}

function saveState() {
  localStorage.setItem('ibdp-bm-v2', JSON.stringify({
    completedTopics: [...state.completedTopics],
    masteredCards: [...state.masteredCards],
    darkMode: state.darkMode,
    notes: state.notes,
    sessions: state.sessions,
  }));
}

// ============================================================
// NAVIGATION
// ============================================================
function navigate(sectionId) {
  state.currentSection = sectionId;

  // Hide all sections, show target
  document.querySelectorAll('.content-section').forEach(s => { s.hidden = true; s.classList.remove('active'); });
  const target = document.getElementById('section-' + sectionId);
  if (target) { target.hidden = false; target.classList.add('active'); }

  // Update nav
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  const navItem = document.querySelector(`.nav-item[data-section="${sectionId}"]`);
  if (navItem) navItem.classList.add('active');

  // Update breadcrumb
  updateBreadcrumb(sectionId);

  // Scroll to top
  document.getElementById('mainContent')?.scrollTo(0, 0);

  // Load dynamic content
  if (sectionId === 'flashcards') initFlashcards();
  if (sectionId === 'exam-practice') initExamPractice();
  if (sectionId === 'my-notes') renderNotes();
  if (sectionId === 'study-planner') renderPlanner();

  updateDashboardStats();
}

function updateBreadcrumb(sectionId) {
  const bc = document.getElementById('breadcrumb');
  if (!bc) return;
  const names = {
    dashboard:'Dashboard', toolkit:'BM Toolkit', unit1:'Unit 1', unit2:'Unit 2', unit3:'Unit 3', unit4:'Unit 4', unit5:'Unit 5',
    flashcards:'Flashcards', 'exam-practice':'Exam Practice', 'study-planner':'Study Planner', 'my-notes':'My Notes'
  };
  bc.innerHTML = `<a href="#" class="breadcrumb-link" onclick="navigate('dashboard');return false"><i class="fas fa-home"></i></a>`;
  if (sectionId !== 'dashboard') {
    bc.innerHTML += ` <span class="breadcrumb-sep">/</span> <span class="breadcrumb-current">${names[sectionId] || sectionId}</span>`;
  }
}

// ============================================================
// POPULATE CONTENT
// ============================================================
function populateAllContent() {
  // Fill topic content panels
  for (const [id, html] of Object.entries(CONTENT)) {
    const el = document.getElementById('content-' + id);
    if (el) el.innerHTML = html;
  }

  // Fill toolkit
  const toolkitGrid = document.getElementById('toolkitGrid');
  if (toolkitGrid) {
    toolkitGrid.innerHTML = TOOLKIT_CONTENT.map(t => `
      <div class="card toolkit-card">
        <div class="card-body">${t.content}</div>
      </div>
    `).join('');
  }
}

// ============================================================
// TAB NAVIGATION
// ============================================================
function setupTabs() {
  document.querySelectorAll('.topic-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      const tabId = tab.dataset.tab;
      const container = tab.closest('.content-section');

      // Update tab buttons
      container.querySelectorAll('.topic-tab').forEach(t => {
        t.classList.toggle('active', t === tab);
        t.setAttribute('aria-selected', t === tab ? 'true' : 'false');
      });

      // Update panels
      container.querySelectorAll('.topic-panel').forEach(p => {
        const isTarget = p.dataset.panel === tabId;
        p.classList.toggle('active', isTarget);
        p.hidden = !isTarget;
      });
    });
  });
}

// ============================================================
// MARK COMPLETE
// ============================================================
function setupMarkComplete() {
  document.querySelectorAll('.mark-complete-btn').forEach(btn => {
    const topic = btn.dataset.topic;
    updateCompleteBtn(btn, topic);

    btn.addEventListener('click', () => {
      if (state.completedTopics.has(topic)) {
        state.completedTopics.delete(topic);
      } else {
        state.completedTopics.add(topic);
      }
      updateCompleteBtn(btn, topic);
      saveState();
      updateDashboardStats();
      showToast(state.completedTopics.has(topic) ? 'Topic marked as complete!' : 'Topic unmarked.');
    });
  });
}

function updateCompleteBtn(btn, topic) {
  const done = state.completedTopics.has(topic);
  btn.innerHTML = done ? '<i class="fas fa-check-circle"></i> Completed' : '<i class="far fa-check-circle"></i> Mark as Complete';
  btn.classList.toggle('btn-success', done);
  btn.classList.toggle('btn-outline', !done);
}

// ============================================================
// DASHBOARD STATS
// ============================================================
function updateDashboardStats() {
  const allTopics = Object.keys(CONTENT);
  const totalTopics = allTopics.length;
  const completed = allTopics.filter(t => state.completedTopics.has(t)).length;
  const pct = Math.round((completed / totalTopics) * 100);

  // Header progress
  const label = document.getElementById('progressLabel');
  if (label) label.textContent = pct + '%';

  const ring = document.querySelector('.progress-ring-fill');
  if (ring) {
    const circumference = 2 * Math.PI * 15;
    ring.style.strokeDasharray = circumference;
    ring.style.strokeDashoffset = circumference - (pct / 100) * circumference;
  }

  // Dashboard stats
  const so = document.getElementById('statOverall');
  if (so) so.textContent = pct + '%';
  const sob = document.getElementById('statOverallBar');
  if (sob) sob.style.width = pct + '%';

  const st = document.getElementById('statTopics');
  if (st) st.textContent = `${completed} / ${totalTopics}`;
  const stb = document.getElementById('statTopicsBar');
  if (stb) stb.style.width = pct + '%';

  const sf = document.getElementById('statFlashcards');
  if (sf) sf.textContent = state.masteredCards.size;
  const sfb = document.getElementById('statFlashcardsBar');
  if (sfb) sfb.style.width = Math.round((state.masteredCards.size / FLASHCARDS.length) * 100) + '%';

  // Unit progress bars
  const unitTopics = { 1: ['1.1','1.2','1.3','1.4','1.5','1.6'], 2: ['2.1','2.2','2.3','2.4','2.6'], 3: ['3.1','3.2','3.3','3.4','3.5','3.7','3.8'], 4: ['4.1','4.2','4.4','4.5'], 5: ['5.1','5.2','5.4','5.5'] };
  for (const [u, topics] of Object.entries(unitTopics)) {
    const c = topics.filter(t => state.completedTopics.has(t)).length;
    const p = Math.round((c / topics.length) * 100);
    const bar = document.getElementById(`unit${u}Bar`);
    const pctEl = document.getElementById(`unit${u}Pct`);
    const inlineBar = document.getElementById(`unit${u}InlineBar`);
    const inlinePct = document.getElementById(`unit${u}InlinePct`);
    if (bar) bar.style.width = p + '%';
    if (pctEl) pctEl.textContent = p + '%';
    if (inlineBar) inlineBar.style.width = p + '%';
    if (inlinePct) inlinePct.textContent = p + '% complete';
  }
}

// ============================================================
// FLASHCARDS
// ============================================================
function initFlashcards() {
  state.flashcardDeck = [...FLASHCARDS];
  state.flashcardIndex = 0;
  state.flashcardFlipped = false;
  renderFlashcard();

  document.getElementById('flashcardProgress').textContent = `Card 1 of ${FLASHCARDS.length}`;
  document.getElementById('flashcardScore').textContent = `Mastered: ${state.masteredCards.size}`;
}

function renderFlashcard() {
  const card = state.flashcardDeck[state.flashcardIndex];
  if (!card) return;

  const front = document.getElementById('flashcardFront');
  const back = document.getElementById('flashcardBack');
  if (front) front.innerHTML = `<p class="flashcard-term">${card.term}</p><p class="flashcard-hint">Click to flip</p>`;
  if (back) back.innerHTML = `<p class="flashcard-definition">${card.def}</p>`;

  const fc = document.getElementById('flashcard');
  if (fc) fc.classList.toggle('flipped', state.flashcardFlipped);

  document.getElementById('flashcardProgress').textContent = `Card ${state.flashcardIndex + 1} of ${state.flashcardDeck.length}`;
  document.getElementById('flashcardScore').textContent = `Mastered: ${state.masteredCards.size} / ${FLASHCARDS.length}`;

  const prev = document.getElementById('flashcardPrev');
  const next = document.getElementById('flashcardNext');
  if (prev) prev.disabled = state.flashcardIndex === 0;
  if (next) next.disabled = state.flashcardIndex >= state.flashcardDeck.length - 1;

  // Show rating after flip
  const rating = document.getElementById('flashcardRating');
  if (rating) rating.hidden = !state.flashcardFlipped;
}

function setupFlashcardControls() {
  document.getElementById('flashcardFlip')?.addEventListener('click', () => {
    state.flashcardFlipped = !state.flashcardFlipped;
    renderFlashcard();
  });

  document.getElementById('flashcardContainer')?.addEventListener('click', () => {
    state.flashcardFlipped = !state.flashcardFlipped;
    renderFlashcard();
  });

  document.getElementById('flashcardPrev')?.addEventListener('click', () => {
    if (state.flashcardIndex > 0) { state.flashcardIndex--; state.flashcardFlipped = false; renderFlashcard(); }
  });

  document.getElementById('flashcardNext')?.addEventListener('click', () => {
    if (state.flashcardIndex < state.flashcardDeck.length - 1) { state.flashcardIndex++; state.flashcardFlipped = false; renderFlashcard(); }
  });

  // Rating buttons
  document.querySelectorAll('.rating-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const card = state.flashcardDeck[state.flashcardIndex];
      if (!card) return;
      const rating = parseInt(btn.dataset.rating);
      if (rating === 3) {
        state.masteredCards.add(card.term);
        showToast('Marked as mastered!');
      }
      saveState();
      // Auto-advance
      if (state.flashcardIndex < state.flashcardDeck.length - 1) {
        state.flashcardIndex++;
        state.flashcardFlipped = false;
        renderFlashcard();
      }
    });
  });

  // Unit filter
  document.getElementById('flashcardUnit')?.addEventListener('change', (e) => {
    // For simplicity, show all cards (no unit tagging in this version)
    state.flashcardDeck = [...FLASHCARDS];
    state.flashcardIndex = 0;
    state.flashcardFlipped = false;
    renderFlashcard();
  });
}

// ============================================================
// EXAM PRACTICE
// ============================================================
function initExamPractice() {
  // Already has static HTML, just wire up the generate button
}

function setupExamPractice() {
  const genBtn = document.getElementById('generateQuestion');
  if (!genBtn) return;

  genBtn.addEventListener('click', () => {
    const paperFilter = document.getElementById('examPaper')?.value;
    const yearFilter = document.getElementById('examYear')?.value;
    const unitFilter = document.getElementById('examUnit')?.value;
    const typeFilter = document.getElementById('examType')?.value;

    let filtered = [...EXAM_QUESTIONS];
    if (paperFilter !== 'all') filtered = filtered.filter(q => q.paper === paperFilter);
    if (yearFilter !== 'all') filtered = filtered.filter(q => q.session === yearFilter);
    if (unitFilter !== 'all') filtered = filtered.filter(q => q.unit === parseInt(unitFilter));
    if (typeFilter === 'short') filtered = filtered.filter(q => q.marks <= 6);
    if (typeFilter === 'essay') filtered = filtered.filter(q => q.marks >= 10);
    if (filtered.length === 0) { showToast('No questions match filters.'); return; }

    const q = filtered[Math.floor(Math.random() * filtered.length)];

    const area = document.getElementById('examQuestionArea');
    area.innerHTML = `
      <div class="exam-question-card">
        <div class="question-meta">
          <span class="badge badge-paper">${q.paper}</span>
          <span class="badge badge-tz">${q.tz}</span>
          <span class="badge badge-year">${q.year}</span>
          <span class="badge">Q${q.qNum}</span>
          <span class="badge badge-marks">${q.marks} marks</span>
          <span class="badge badge-command">${q.command}</span>
        </div>
        <div class="question-source">
          <span><strong>Case Study:</strong> ${q.caseStudy}</span>
          <span><strong>Topic:</strong> Unit ${q.unit} &middot; ${q.section}</span>
        </div>
        <p class="question-text"><strong>${q.q}</strong></p>
      </div>
    `;

    const ansArea = document.getElementById('examAnswerArea');
    if (ansArea) ansArea.hidden = false;

    const msArea = document.getElementById('examMarkScheme');
    if (msArea) {
      msArea.hidden = true;
      msArea.innerHTML = `
        <div class="markscheme-card">
          <div class="markscheme-header">
            <h4><i class="fas fa-check-circle"></i> Official IB Mark Scheme</h4>
            <span class="badge badge-marks">${q.marks} marks</span>
          </div>
          <div class="markscheme-source">${q.paper} &middot; ${q.year} &middot; ${q.tz} &middot; ${q.caseStudy} &middot; Q${q.qNum}</div>
          <div class="markscheme-content">${q.a}</div>
        </div>
      `;
    }
  });

  document.getElementById('showMarkScheme')?.addEventListener('click', () => {
    const ms = document.getElementById('examMarkScheme');
    if (ms) ms.hidden = false;
  });

  document.getElementById('clearAnswer')?.addEventListener('click', () => {
    const ta = document.getElementById('examAnswer');
    if (ta) ta.value = '';
  });
}

// ============================================================
// NOTES
// ============================================================
function renderNotes() {
  const list = document.getElementById('notesList');
  if (!list) return;

  if (state.notes.length === 0) {
    list.innerHTML = '<p class="empty-state">No notes yet. Add notes while studying or create a new note above.</p>';
    return;
  }

  list.innerHTML = state.notes.map((n, i) => `
    <div class="card note-card">
      <div class="card-body">
        <h4>${n.title} <span class="badge">${n.topic}</span></h4>
        <p>${n.content.substring(0, 200)}${n.content.length > 200 ? '...' : ''}</p>
        <div class="note-actions">
          <button class="btn btn-sm btn-outline" onclick="editNote(${i})"><i class="fas fa-edit"></i> Edit</button>
          <button class="btn btn-sm btn-danger" onclick="deleteNote(${i})"><i class="fas fa-trash"></i></button>
        </div>
      </div>
    </div>
  `).join('');
}

function setupNotes() {
  document.getElementById('addNoteBtn')?.addEventListener('click', () => {
    document.getElementById('noteTitle').value = '';
    document.getElementById('noteContent').value = '';
    document.getElementById('noteTopic').value = 'general';
    document.getElementById('noteEditorTitle').textContent = 'New Note';
    document.getElementById('deleteNote').hidden = true;
    document.getElementById('noteEditorModal').hidden = false;
    document.getElementById('saveNote').onclick = () => {
      state.notes.push({
        title: document.getElementById('noteTitle').value || 'Untitled',
        topic: document.getElementById('noteTopic').value,
        content: document.getElementById('noteContent').value,
        date: new Date().toISOString()
      });
      saveState();
      document.getElementById('noteEditorModal').hidden = true;
      renderNotes();
      showToast('Note saved!');
    };
  });
}

window.editNote = function(i) {
  const n = state.notes[i];
  if (!n) return;
  document.getElementById('noteTitle').value = n.title;
  document.getElementById('noteContent').value = n.content;
  document.getElementById('noteTopic').value = n.topic;
  document.getElementById('noteEditorTitle').textContent = 'Edit Note';
  document.getElementById('deleteNote').hidden = false;
  document.getElementById('noteEditorModal').hidden = false;
  document.getElementById('saveNote').onclick = () => {
    state.notes[i] = { ...n, title: document.getElementById('noteTitle').value, content: document.getElementById('noteContent').value, topic: document.getElementById('noteTopic').value };
    saveState();
    document.getElementById('noteEditorModal').hidden = true;
    renderNotes();
    showToast('Note updated!');
  };
  document.getElementById('deleteNote').onclick = () => { deleteNote(i); document.getElementById('noteEditorModal').hidden = true; };
};

window.deleteNote = function(i) {
  if (!confirm('Delete this note?')) return;
  state.notes.splice(i, 1);
  saveState();
  renderNotes();
  showToast('Note deleted.');
};

